const text = $input.item.json.output || '';
const match = text.match(/```json\s*([\s\S]*?)\s*```/);

if (match) {
  try {
    const parsed = JSON.parse(match[1].trim());
    if (!Array.isArray(parsed.terms)) parsed.terms = [];
    return { json: parsed };
  } catch (e) {
    return { json: { found: false, terms: [], error: 'Parsing error: ' + e.message, raw: text } };
  }
}

return { json: { found: false, terms: [], error: 'No JSON block found', raw: text } };

const terms = $input.item.json.terms || [];

const lines = terms.map((t, i) => `${i + 1}. *${t.term}*\n   ${t.definition}`);

const message = `📚 *Post-Call Glossary*\n_${terms.length} term${terms.length === 1 ? '' : 's'} found_\n\n${lines.join('\n\n')}`;

return { json: { message } };
